private fun RssFeedBottomSheet(
    username: String,
    onDismiss: () -> Unit
) {
    val context = LocalContext.current
    val colors = LocalAppColors.current
    val typography = LocalAppTypography.current
    val clipboardManager = context.getSystemService(
        android.content.Context.CLIPBOARD_SERVICE
    ) as android.content.ClipboardManager

    fun openFeed(feedUrl: String) {
        try {
            val intent = Intent(Intent.ACTION_VIEW).apply {
                setDataAndType(
                    android.net.Uri.parse(feedUrl),
                    "application/rss+xml"
                )
                addCategory(Intent.CATEGORY_BROWSABLE)
            }
            context.startActivity(intent)
        } catch (_: android.content.ActivityNotFoundException) {
            clipboardManager.setPrimaryClip(
                android.content.ClipData.newPlainText("RSS Feed URL", feedUrl)
            )
            android.widget.Toast.makeText(
                context,
                "Feed URL copied to clipboard",
                android.widget.Toast.LENGTH_SHORT
            ).show()
        }
        onDismiss()
    }

    ModalBottomSheet(
        onDismissRequest = onDismiss,
        sheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp)
                .padding(bottom = 32.dp)
        ) {
            Text(
                text = "RSS Feed",
                style = typography.bodyLargeSemiBold,
                color = colors.textPrimary,
                modifier = Modifier.padding(bottom = 16.dp)
            )

            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier
                    .fillMaxWidth()
                    .clip(RoundedCornerShape(8.dp))
                    .clickable { openFeed("https://hackers.pub/@$username/feed.xml") }
                    .padding(vertical = 12.dp)
            ) {
                Icon(
                    imageVector = Icons.Outlined.RssFeed,
                    contentDescription = null,
                    tint = colors.accent,
                    modifier = Modifier.size(24.dp)
                )
                Spacer(modifier = Modifier.width(12.dp))
                Column {
                    Text(
                        text = "All Posts",
                        style = typography.bodyLargeSemiBold,
                        color = colors.textPrimary
                    )
                    Text(
                        text = "@$username/feed.xml",
                        style = typography.labelMedium,
                        color = colors.textSecondary
                    )
                }
            }

            HorizontalDivider(color = colors.divider, thickness = 1.dp)

            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier
                    .fillMaxWidth()
                    .clip(RoundedCornerShape(8.dp))
                    .clickable { openFeed("https://hackers.pub/@$username/feed.xml?articles") }
                    .padding(vertical = 12.dp)
            ) {
                Icon(
                    imageVector = Icons.Outlined.RssFeed,
                    contentDescription = null,
                    tint = colors.accent,
                    modifier = Modifier.size(24.dp)
                )
                Spacer(modifier = Modifier.width(12.dp))
                Column {
                    Text(
                        text = "Articles Only",
                        style = typography.bodyLargeSemiBold,
                        color = colors.textPrimary
                    )
                    Text(
                        text = "@$username/feed.xml?articles",
                        style = typography.labelMedium,
                        color = colors.textSecondary
                    )
                }
            }
        }
    }
}

